import akshare as ak
import pandas as pd

print("获取A股财务数据...")

# 方法1: 获取全部A股财务指标
try:
    df = ak.stock_financial_analysis_indicator_em(symbol="A股")
    print(f"方法1成功: {len(df)} 条")
    print(df.columns.tolist()[:10])
except Exception as e:
    print(f"方法1失败: {e}")

# 方法2: 获取财务摘要
print("\n方法2: 获取财务摘要...")
try:
    stocks = ak.stock_info_a_code_name()['code'].tolist()[:5]
    all_data = []
    for s in stocks:
        try:
            fin = ak.stock_financial_abstract_ths(symbol=s)
            if len(fin) > 0:
                fin['code'] = s
                all_data.append(fin)
        except:
            pass
    if all_data:
        result = pd.concat(all_data)
        print(f"方法2成功: {len(result)} 条")
except Exception as e:
    print(f"方法2失败: {e}")
EOF
